import React, { useEffect, useRef } from 'react';
import { graphql, Link, useStaticQuery } from 'gatsby';
import styled from 'styled-components';
import { srConfig } from '@config';
import sr from '@utils/sr';
import { usePrefersReducedMotion } from '@hooks';

const StyledBlogPreviewSection = styled.section`
  display: flex;
  flex-direction: column;
  align-items: center;

  .header-row {
    ${({ theme }) => theme.mixins.flexBetween};
    width: 100%;
    align-items: flex-end;
    gap: 14px;
  }

  .all-posts-link {
    font-size: var(--fz-sm);
    font-weight: 600;
    font-family: var(--font-ui);
    white-space: nowrap;
    flex-shrink: 0;

    &:after {
      bottom: 0.1em;
    }
  }

  .posts-grid {
    ${({ theme }) => theme.mixins.resetList};
    width: 100%;
    display: grid;
    grid-template-columns: repeat(3, minmax(0, 1fr));
    gap: 20px;
    margin-top: 34px;

    @media (max-width: 1080px) {
      grid-template-columns: repeat(2, minmax(0, 1fr));
    }

    @media (max-width: 700px) {
      grid-template-columns: 1fr;
    }
  }
`;

const StyledPost = styled.li`
  .post-card {
    ${({ theme }) => theme.mixins.boxShadow};
    ${({ theme }) => theme.mixins.flexBetween};
    flex-direction: column;
    align-items: flex-start;
    height: 100%;
    border-radius: var(--border-radius);
    background-color: var(--surface-secondary);
    padding: 1.65rem 1.45rem 1.3rem;
    transition: var(--transition);
  }

  @media (prefers-reduced-motion: no-preference) {
    &:hover,
    &:focus-within {
      .post-card {
        transform: translateY(-6px);
      }
    }
  }

  .post-title {
    margin: 0 0 8px;
    color: var(--lightest-slate);
    font-size: clamp(20px, 2.3vw, 24px);
    line-height: 1.2;

    a {
      position: static;

      &:before {
        content: '';
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
      }
    }
  }

  .post-desc {
    position: relative;
    margin: 0;
    color: var(--dark-slate);
    font-size: var(--fz-sm);
    line-height: 1.55;
    max-height: calc(1.55em * 3);
    overflow: hidden;

    &:after {
      content: '';
      position: absolute;
      left: 0;
      right: 0;
      bottom: 0;
      height: 1.5em;
      background: linear-gradient(180deg, rgba(248, 246, 242, 0), var(--surface-secondary));
      pointer-events: none;
    }
  }

  .post-footer {
    ${({ theme }) => theme.mixins.flexBetween};
    width: 100%;
    align-items: flex-start;
    gap: 8px 12px;
    flex-wrap: wrap;
    margin-top: 18px;
    padding-top: 12px;
    border-top: 1px solid var(--lightest-navy);
  }

  .post-date {
    color: var(--light-slate);
    font-family: var(--font-mono);
    font-size: var(--fz-xxs);
    text-transform: uppercase;
    white-space: nowrap;
  }

  .post-tags {
    ${({ theme }) => theme.mixins.resetList};
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
  }

  .post-tag {
    color: var(--green);
    font-family: var(--font-mono);
    font-size: var(--fz-xxs);
    line-height: 1.4;
  }
`;

const HomeBlogPreview = () => {
  const data = useStaticQuery(graphql`
    query {
      posts: allMarkdownRemark(
        filter: { fileAbsolutePath: { regex: "/content/posts/" }, frontmatter: { draft: { ne: true } } }
        sort: { fields: [frontmatter___date], order: DESC }
        limit: 3
      ) {
        edges {
          node {
            frontmatter {
              title
              description
              slug
              date
              tags
            }
          }
        }
      }
    }
  `);

  const revealTitle = useRef(null);
  const revealLink = useRef(null);
  const revealPosts = useRef([]);
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    if (prefersReducedMotion) {
      return;
    }

    sr.reveal(revealTitle.current, srConfig());
    sr.reveal(revealLink.current, srConfig());
    revealPosts.current.forEach((ref, i) => sr.reveal(ref, srConfig(i * 100)));
  }, []);

  const posts = data.posts.edges.filter(({ node }) => node);

  return (
    <StyledBlogPreviewSection>
      <div className="header-row">
        <h2 className="numbered-heading" ref={revealTitle}>
          Latest Insights
        </h2>
        <Link to="/blog" className="inline-link all-posts-link" ref={revealLink}>
          Read All Posts
        </Link>
      </div>

      <ul className="posts-grid">
        {posts.map(({ node }, i) => {
          const { title, description, slug, date, tags } = node.frontmatter;

          return (
            <StyledPost key={slug} ref={el => (revealPosts.current[i] = el)}>
              <article className="post-card">
                <header>
                  <h3 className="post-title">
                    <Link to={slug}>{title}</Link>
                  </h3>
                  <p className="post-desc">{description}</p>
                </header>

                <footer className="post-footer">
                  <span className="post-date">{new Date(date).toLocaleDateString()}</span>
                  <ul className="post-tags">
                    {(tags || []).slice(0, 3).map(tag => (
                      <li className="post-tag" key={`${slug}-${tag}`}>
                        #{tag}
                      </li>
                    ))}
                  </ul>
                </footer>
              </article>
            </StyledPost>
          );
        })}
      </ul>
    </StyledBlogPreviewSection>
  );
};

export default HomeBlogPreview;
