import React, { useEffect, useState } from 'react';
import styled from 'styled-components';
import { usePrefersReducedMotion } from '@hooks';
import { trackEvent } from '@utils';

const StyledBackToTop = styled.button`
  position: fixed;
  right: 24px;
  bottom: 24px;
  width: 46px;
  height: 46px;
  border-radius: 999px;
  border: 1px solid var(--lightest-navy);
  background-color: var(--light-navy);
  color: var(--green);
  box-shadow: 0 8px 24px -16px var(--navy-shadow);
  font-size: 20px;
  font-weight: 700;
  line-height: 1;
  display: ${({ $isVisible }) => ($isVisible ? 'inline-flex' : 'none')};
  align-items: center;
  justify-content: center;
  z-index: 20;
  transition: var(--transition);

  &:hover,
  &:focus-visible {
    transform: translateY(-2px);
    box-shadow: 0 14px 30px -18px var(--navy-shadow);
  }

  @media (max-width: 768px) {
    right: 16px;
    bottom: 16px;
  }
`;

const BackToTop = () => {
  const [isVisible, setIsVisible] = useState(false);
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    const onScroll = () => {
      setIsVisible(window.scrollY > 550);
    };

    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();

    return () => {
      window.removeEventListener('scroll', onScroll);
    };
  }, []);

  const scrollToTop = () => {
    trackEvent({
      category: 'cta',
      action: 'click_back_to_top',
      label: 'Back To Top Button',
    });

    window.scrollTo({
      top: 0,
      behavior: prefersReducedMotion ? 'auto' : 'smooth',
    });
  };

  return (
    <StyledBackToTop type="button" $isVisible={isVisible} onClick={scrollToTop} aria-label="Back to top">
      ↑
    </StyledBackToTop>
  );
};

export default BackToTop;
